SELECT symbol FROM etfs WHERE symbol IN (
  SELECT table_name FROM information_schema.tables
) AND (
  SELECT COUNT(*) FROM (
    SELECT 1 FROM (
      SELECT Date, [Adj Close] FROM (SELECT * FROM "' || symbol || '") WHERE (
        COALESCE(TRY_STRPTIME(Date, '%Y-%m-%d'), TRY_STRPTIME(Date, '%m/%d/%Y'), TRY_STRPTIME(Date, '%Y/%m/%d')) BETWEEN DATE '2015-01-01' AND DATE '2015-12-31'
      ) AND [Adj Close] > 200
    )
  ) > 0
)

SELECT COUNT(*) AS up_days FROM "AEFC" WHERE COALESCE(
  TRY_STRPTIME("Date", '%Y-%m-%d'),
  TRY_STRPTIME("Date", '%m/%d/%Y'),
  TRY_STRPTIME("Date", '%Y/%m/%d'),
  TRY_STRPTIME("Date", '%d-%b-%y')
) BETWEEN DATE '2017-01-01' AND DATE '2017-12-31' AND "Close" > "Open";

